import{_ as t,p as e,q as i,a1 as l}from"./framework-96b046e1.js";const r={},a=l('<p>直流有刷电机就是我们小时候玩的四驱车里边的小马达，两根线通上直流电就会转起来，电压越高转速越快。</p><p>改变正负极可使电机转向反转。</p><ul><li>电机调速，通过改变电机电枢两端的电压。</li><li>电机速度越高，产生的反电动势越大。反电动势与电机转速成正比。</li><li>流过电机线圈的电流：I=(U-E)/R。<em>（U为电机两端电压，E为反电动势，R为线圈电阻）</em></li><li>当电机<strong>堵转</strong>，或者刚启动时（速度为0），此时反电动势为0，电压全加在线圈上，此时<strong>电流很大(长时间堵转会烧毁电机！！！）</strong>。</li><li>电机的转矩，与电流成正比。因此，负载越重，所需电磁转矩越大，电流也就越大。</li><li>当电机从稳态加上一个负载，电机速度下降，反电动势下降，电流增加，转矩加大。如果这个转矩还是不够带动负载，则速度继续下降，当下降某个速度，电机转矩等于负载转矩，则进入稳态。若直到速度为0，还是不够带动负载，则发生<strong>堵转</strong>。</li></ul><h2 id="电机选型" tabindex="-1"><a class="header-anchor" href="#电机选型" aria-hidden="true">#</a> 电机选型</h2><p>选择电机参数时要注意：额定扭矩、额定电流。</p><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>小窍门：在满足重量要求的情况下，尽量挑功率大的。</p></div><h2 id="测速方法" tabindex="-1"><a class="header-anchor" href="#测速方法" aria-hidden="true">#</a> 测速方法</h2><ul><li>光电编码器</li><li>磁电编码器</li></ul>',8),s=[a];function o(n,c){return e(),i("div",null,s)}const h=t(r,[["render",o],["__file","brush-motor.html.vue"]]);export{h as default};
